import { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../api/axios';
import { useAuth } from '../context/AuthContext';

const STATUS_COLOR = { Pending: '#f59e0b', Approved: '#10b981', Rejected: '#ef4444' };

export default function EmployeeDashboard() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [expenses, setExpenses] = useState([]);

  useEffect(() => {
    api.get('/expenses').then((res) => setExpenses(res.data));
  }, []);

  return (
    <div style={styles.page}>
      <header style={styles.header}>
        <h2>My Expenses</h2>
        <div>
          <button style={styles.btnPrimary} onClick={() => navigate('/employee/submit')}>+ Submit Expense</button>
          <button style={styles.btnLogout} onClick={logout}>Logout</button>
        </div>
      </header>
      <p>Welcome, {user?.name}</p>
      <table style={styles.table}>
        <thead>
          <tr>{['Date', 'Category', 'Amount', 'Currency', 'Status', 'Detail'].map((h) => <th key={h} style={styles.th}>{h}</th>)}</tr>
        </thead>
        <tbody>
          {expenses.map((e) => (
            <tr key={e._id}>
              <td style={styles.td}>{new Date(e.date).toLocaleDateString()}</td>
              <td style={styles.td}>{e.category}</td>
              <td style={styles.td}>{e.amount}</td>
              <td style={styles.td}>{e.currency}</td>
              <td style={styles.td}><span style={{ color: STATUS_COLOR[e.status] }}>{e.status}</span></td>
              <td style={styles.td}><Link to={`/expenses/${e._id}`}>View</Link></td>
            </tr>
          ))}
          {expenses.length === 0 && <tr><td colSpan={6} style={{ textAlign: 'center', padding: '1rem' }}>No expenses yet</td></tr>}
        </tbody>
      </table>
    </div>
  );
}

const styles = {
  page: { maxWidth: '900px', margin: '2rem auto', padding: '0 1rem' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' },
  btnPrimary: { padding: '0.5rem 1rem', background: '#4f46e5', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer', marginRight: '0.5rem' },
  btnLogout: { padding: '0.5rem 1rem', background: '#ef4444', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' },
  table: { width: '100%', borderCollapse: 'collapse' },
  th: { background: '#f3f4f6', padding: '0.6rem', textAlign: 'left', borderBottom: '1px solid #e5e7eb' },
  td: { padding: '0.6rem', borderBottom: '1px solid #e5e7eb' },
};
